def get_gas_coeff(name, inu):
    """
    Return the 8 absorption coefficients for gas table `name` at interval `inu`.
    
    Parameters
    ----------
    name : str  – table name (e.g. "wava1", "ozon1", "meth3")
    inu  : int  – 1-based interval index (1..256)
    
    Returns
    -------
    a : list of 8 floats
    """
    return list(_TABLES[name][inu - 1])
